#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_POSITION 10000000000.0
#define PRECISION 0.00005

bool check(double* position, int N, double T, double mid) {
    double currPos = position[N - 1] + mid;
    for (int i = N - 2; i >= 0; i--) {
        currPos -= T;
        if (currPos > position[i] + mid) {
            currPos = position[i] + mid;
        } else if (currPos < position[i] - mid) {
            return false;
        }
    }
    return currPos >= 0.0;
}

void solve() {
    int N;
    double T;
    scanf("%d %lf", &N, &T);

    double* position = (double*)malloc(N * sizeof(double));
    for (int i = 0; i < N; i++) {
        scanf("%lf", &position[i]);
    }

    double low = 0.0, high = MAX_POSITION, ans = 0.0;
    while ((high - low) > PRECISION) {
        double mid = (low + high) / 2.0;
        if (check(position, N, T, mid)) {
            ans = mid;
            high = mid;
        } else {
            low = mid;
        }
    }

    printf("%.4lf\n", ans);
    free(position); // Free allocated memory
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        solve();
    }
    return 0;
}

