import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    static boolean check(double[] position, int N, double T, double mid) {
        double currPos = position[N - 1] + mid;
        for (int i = N - 2; i >= 0; i--) {
            currPos -= T;
            if (currPos > position[i] + mid) {
                currPos = position[i] + mid;
            } else if (currPos < position[i] - mid) {
                return false;
            }
        }
        return currPos >= 0.0;
    }

    // Function to solve the problem for each test case
    static void solve(BufferedReader br) throws IOException {
        StringTokenizer st = new StringTokenizer(br.readLine());
        int N = Integer.parseInt(st.nextToken());
        double T = Double.parseDouble(st.nextToken());

        double[] position = new double[N];
        for (int i = 0; i < N; i++) {
            position[i] = Double.parseDouble(br.readLine());
        }

        double low = 0.0, high = 10000000000.0, ans = 0.0;
        while ((high - low) > 0.00001) {  // Reduce epsilon to fine-tune the precision
            double mid = (low + high) / 2.0;
            if (check(position, N, T, mid)) {
                ans = mid;
                high = mid;
            } else {
                low = mid;
            }
        }

        // Print the answer with 4 decimal precision
        System.out.printf("%.4f\n", ans);
    }

    public static void main(String[] args) throws IOException {
        // Faster input reading using BufferedReader
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int K = Integer.parseInt(br.readLine());  // Number of test cases

        while (K-- > 0) {
            solve(br);
        }
    }
}
